def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 3:
            priorities[i] = ratio ** 4 + np.exp(ratio - 3)
            if capacity < item:
                priorities[i] += (item - capacity) * 20
        elif 1 < ratio <= 3:
            val = 0
            for k in range(1, int(capacity) + 1):
                if k % 2 == 0:
                    val += (ratio ** k) / (k**2)
                else:
                    val -= (ratio ** k) / (k**2)
            priorities[i] = val if val != 0 else 2
            if capacity < item:
                priorities[i] += (item - capacity) * 15
        elif 0.3 < ratio <= 1:
            try:
                priorities[i] = -np.log(1 - ratio + 1e-10) + np.sin(5 * ratio) * 0.5
            except FloatingPointError:
                priorities[i] = 10
        else:
            val = 0
            for j in range(1, int(capacity) + 1):
                term = (ratio ** j) / (j * np.math.factorial(j))
                if j % 3 == 0:
                    term *= -1
                val += term
            priorities[i] = val if val != 0 else 0.5
        if capacity < item and ratio < 1:
            priorities[i] += ((item - capacity) ** 2) / (capacity + 1)
        if priorities[i] < 0:
            priorities[i] = abs(priorities[i]) * 0.1
    return priorities
